module RefModule(
    output reg [3:0] douta,
    input clka,
    input ena,
    input [3:0] addra
);// Memory array declaration (16 entries of 4 bits each)
reg [3:0] obf_mem [0:15];

// Initialize the memory contents
initial begin
    // Example initialization, you can modify according to your requirements
    obf_mem[0] = 4'b0000;
    obf_mem[1] = 4'b0001;
    obf_mem[2] = 4'b0010;
    obf_mem[3] = 4'b0011;
    obf_mem[4] = 4'b0100;
    obf_mem[5] = 4'b0101;
    obf_mem[6] = 4'b0110;
    obf_mem[7] = 4'b0111;
    obf_mem[8] = 4'b1000;
    obf_mem[9] = 4'b1001;
    obf_mem[10] = 4'b1010;
    obf_mem[11] = 4'b1011;
    obf_mem[12] = 4'b1100;
    obf_mem[13] = 4'b1101;
    obf_mem[14] = 4'b1110;
    obf_mem[15] = 4'b1111;
end

always @(posedge clka) begin
    if (ena) begin
        douta <= obf_mem[addra]; // Output data from memory based on address
    end
end

endmodule
